import type { GeoJSON } from "geojson"

declare module "hxmap" {
  // 地图
  type IMapEvent = keyof GlobalEventHandlersEventMap | "moveend"
  type IMapEventCallback = (data: {
    latlon: { lon: number; lat: number }
    offsetX: number
    offsetY: number
    type: IMapEvent
  }) => void
  type IMapInstance = {
    getZoom: () => number
    getCenter: () => { lon: number; lat: number }
    setZoom: (zoom: number) => void
    setView: (lat: number, lon: number, zoom: number) => void
    on: (event: IMapEvent, callback: IMapEventCallback) => void
    off: (event: IMapEvent, callback: IMapEventCallback) => void
    hasLayer: (layer: ILayer) => boolean
    setDragable: (dragable: boolean) => void
    resizeEvent: () => void
    sync: (mapInstance: IMapInstance) => void
    setLayerEvent: (
      event: IMapEvent,
      layer: ILayer,
      callback: IMapEventCallback
    ) => void
  }
  type IMapOptions = {
    content: string | HTMLElement
    center: [lat: number, lon: number]
    zoom: number
    minZoom?: number
    maxZoom?: number
    preserveDrawingBuffer?: boolean
  }
  const Map: new (params: IMapOptions) => IMapInstance

  // 基础图层
  interface ILayer {
    addTo: (target: IMapInstance | ILayerGroupInstance) => this
    removeFromMap: (target: IMapInstance | ILayerGroupInstance) => void
    destroy: (target: IMapInstance | ILayerGroupInstance) => void
  }

  // 图层组
  interface ILayerGroupInstance extends ILayer {
    addLayer: (layer: ILayer) => void
    removeLayer: (layer: ILayer) => void
    clearLayers: (destroy: boolean) => void
  }
  const LayerGroup: new () => ILayerGroupInstance

  // 瓦片图层
  interface ITileLayerInstance extends ILayer { }
  const TileLayer: new (params: {
    url?: string
    index?: number
    target?: string
    customUrlFun?: (z: number, x: number, y: number) => string
  }) => ITileLayerInstance

  // 矢量瓦片
  interface IGVectorTileInstance extends ILayer { }
  const GVectorTile: new (params: {
    url: string
    style: unknown
    index?: number
  }) => IGVectorTileInstance

  // 矢量标注
  interface IGVectorPointsInstance extends ILayer { }
  const GVectorPoints: new (params: {
    url: string
    style: unknown
    index?: number
  }) => IGVectorPointsInstance

  // 普通标记
  interface IGMarkerInstance extends ILayer {
    bindTooltip: (
      map: IMapInstance,
      content: HTMLElement | string,
      index?: number
    ) => void
  }
  const GMarker: new (params: {
    position: [lat: number, lon: number]
    source: string
    imgSize?: [width: number, height: number]
    index?: number
  }) => IGMarkerInstance

  // div标记
  interface IElMarkerInstance extends ILayer {
    bindTooltip: (
      map: IMapInstance,
      content: HTMLElement | string,
      index?: number
    ) => void
    setLatLng: (lat: number, lon: number) => void
  }
  const ElMarker: new (params: {
    position: [lat: number, lon: number]
    source: HTMLElement | string
    index?: number
    pointEvent?: boolean
  }) => IElMarkerInstance

  // 基础色斑图
  interface IGlImgInstance extends ILayer {
    changeImage: (img: string | HTMLImageElement) => void
    changeImageArea: (
      img: string | HTMLImageElement,
      latmin: number,
      latmax: number,
      lonmin: number,
      lonmax: number,
      others?: { colors?: IColors; grid?: boolean; interval?: number }
    ) => void
    changeColor: (colors: IColors) => void
    changeGrid: (whether: boolean) => void
    setGetGrid: (whether: boolean) => void
    getGridDataByLatLon: (
      lat: number,
      lon: number
    ) => { data: number | null; lon: number; lat: number }
  }
  type IScale = {
    r: number
    g: number
    b: number
    a: number
  }
  type IColors = {
    r: number[]
    g: number[]
    b: number[]
    v: number[]
    o: number[]
  }
  const GlImg: new (params: {
    img: string | HTMLImageElement
    lonmin: number
    lonmax: number
    latmin: number
    latmax: number
    scale: IScale
    colors: IColors
    preserveDrawingBuffer?: boolean
    index?: number
    interval?: number
    grid?: boolean
    linear?: number
    flipy?: 0 | 1
  }) => IGlImgInstance

  // 切片填色图
  interface ISliceImgInstance extends ILayer {
    changeUrl: (url: string) => void
  }
  const SliceImg: new (params: {
    url: string | HTMLImageElement
    scale: IScale
    colors: IColors
    minOpacity?: boolean
    maxTileZoom: number
    index?: number
  }) => ISliceImgInstance

  // 实时色斑图
  interface IJzbImgSocketInstance extends ILayer { }
  const JzbImgSocket: new (params: {
    url: string
    latst: number
    lonst: number
    colors: IColors
    linear?: number
    startCmd: string
    closeCmd: string
    decodeFun: (arraybuffer: ArrayBuffer) =>
      | {
        range: number
        interval: number
        elev: number
        azi: number
        data: number[]
        datanum: number
      }
      | undefined
    index?: number
  }) => IJzbImgSocketInstance

  // 线
  interface IGPolylineInstance extends ILayer {
    changeCoords: (
      coords: [lat: number, lon: number][] | [lat: number, lon: number][]
    ) => void
    changeColor: (color: [r: number, g: number, b: number, a: number]) => void
  }
  const GPolyline: new (params: {
    coords: [lat: number, lon: number][] | [lat: number, lon: number][][]
    lineWidth?: number
    color?: [r: number, g: number, b: number, a: number]
    index?: number
  }) => IGPolylineInstance

  // 文字
  interface IGTextInstance extends ILayer { }
  const GText: new (params: {
    data: { lon: number; lat: number; value: string }[]
    fontSize?: number
    fontColor?: string
    fontWeight?: string
  }) => IGTextInstance

  // geojson线
  interface IGeojsonLinesInstance extends ILayer { }
  const GeojsonLines: new (params: {
    data: GeoJSON
    lineWidth?: number
    color?: [r: number, g: number, b: number, a: number]
    index?: number
  }) => IGeojsonLinesInstance

  // geojson立体效果
  interface GeojsonVolumeInstance extends ILayer { }
  const GeojsonVolume: new (params: {
    data: GeoJSON
    color?: string | [r: number, g: number, b: number, a: number]
    sideTopColor?: string | [r: number, g: number, b: number, a: number]
    sideBottomColor?: string | [r: number, g: number, b: number, a: number]
    offset?: number
    index?: number
  }) => GeojsonVolumeInstance

  // 等经纬剖面
  type IProfileInstance = {
    changeImg: (url: string) => void
    draw: (
      range: [slat: number, slon: number, elat: number, elon: number]
    ) => void
    destroy: () => void
  }
  type IProfileOptions = {
    content: string | HTMLElement
    lonmin: number
    lonmax: number
    latmin: number
    latmax: number
    url: string
    colors: IColors
    loadTxtColor?: string
    onReady?: () => void
  }
  const Profile: new (params: IProfileOptions) => IProfileInstance

  // 实时解码剖面图
  interface IsocketProfileInstance {
    destroy: () => void
  }
  const socketProfile: new (params: {
    content: string | HTMLElement
    url: string
    colors: IColors
    startCmd: string
    decodeFun: (arraybuffer: ArrayBuffer) =>
      | {
        data: number[]
        xnum: number
        ynum: number
      }
      | undefined
  }) => IsocketProfileInstance

  // 散点风向杆
  type IGWindbarData = { lon: number; lat: number; spd: number; dir: number }[]
  interface IGWindbarInstance extends ILayer {
    changeData: (data: IGWindbarData) => void
  }
  const GWindbar: new (params: {
    data: IGWindbarData
    color?: string
    pointSize?: number
    lineWidth?: number
    shadowColor?: string
    shadowWidth?: number
    customWind?: {
      img: HTMLImageElement | HTMLCanvasElement
      valueFun: (value: number) => number
    }
  }) => IGWindbarInstance

  // 网格风向杆
  interface IGridWindbarInstance extends ILayer {
    changeData: (data: { spdUrl: string; dirUrl: string }) => void
  }
  const GridWindbar: new (params: {
    spdUrl: string
    dirUrl: string
    latmin: number
    latmax: number
    lonmin: number
    lonmax: number
    interval: number
    intervalZoom: number
    speedScale: IScale
    dirScale: IScale
    color?: string
    pointSize?: number
    lineWidth?: number
    shadowColor?: string
    shadowWidth?: number
  }) => IGridWindbarInstance

  // 多边形
  type IGPolygonData = [lat: number, lon: number][]
  interface IGPolygonInstance extends ILayer {
    changeColor: (color: string) => void
    changeCoords: (data: IGPolygonData) => void
  }
  const GPolygon: new (params: {
    coords: IGPolygonData
    color?: [r: number, g: number, b: number, a: number]
    index?: number
  }) => IGPolygonInstance

  // 多边形平滑工具方法
  interface IBasisInstance {
    lineStart: () => void
    point: (lat: number, lon: number) => void
    lineEnd: () => void
    points: IGPolygonData
  }
  const Basis: new () => IBasisInstance

  // 点
  interface IPointLayerInstance extends ILayer { }
  const PointLayer: new (params: {
    position: [lat: number, lon: number]
    radius?: number
    lineWidth?: number
    strokeStyle?: string
    fillStyle?: string
    index?: number
  }) => IPointLayerInstance
}
